const incoming = $input.first().json || {};
const body = (incoming.body && typeof incoming.body === 'object' && incoming.body.action) ? incoming.body : incoming;
const action = body.action || '';
const acceptedActions = new Set(['opened', 'ready_for_review', 'reopened', 'synchronize']);

if (!acceptedActions.has(action)) return [];

const pr = body.pull_request || {};
const repo = body.repository || {};
const base = pr.base || {};
const head = pr.head || {};

return [{ json: {
  title: pr.title || '',
  body: pr.body || '(no description)',
  html_url: pr.html_url || '',
  author: (pr.user && pr.user.login) || 'unknown',
  changed_files: pr.changed_files || 0,
  additions: pr.additions || 0,
  deletions: pr.deletions || 0,
  action,
  pr_number: pr.number || body.number || null,
  repo_full_name: repo.full_name || 'paperwork-labs/paperwork',
  base_branch: base.ref || 'main',
  head_branch: head.ref || ''
}}];

