function sanitizeSlackMrkdwn(text) {
  return String(text || '')
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>');
}

const src = $('Filter PR Events').first().json;
const output = $json.output || [];
const aiText = output[0]?.content?.find((part) => part.type === 'output_text')?.text || '';

const fallback = `<${src.html_url || ''}|PR #${src.pr_number || '?'}: ${src.title || 'Untitled'}>\nRepo: ${src.repo_full_name} | ${src.head_branch || '?'} -> ${src.base_branch || '?'}\nChanges: ${src.changed_files} files | +${src.additions} / -${src.deletions}\n\n_No AI summary available. Ask in thread for engineering, legal, QA, growth, social, strategy, partnerships, CPA, or EA._`;

const text = aiText.trim() ? sanitizeSlackMrkdwn(aiText) : sanitizeSlackMrkdwn(fallback);
const routerHint = '_Thread router: reply with `legal`, `growth`, `social`, `qa`, `strategy`, `engineering`, `cpa`, `partnerships`, or `ea` for a focused take._';

return [{ json: { text: sanitizeSlackMrkdwn(`${text}\n\n${routerHint}`) } }];
